// ---- UTILITIES ----
function ls_get(k) {
  try {
    return JSON.parse(localStorage.getItem(k));
  } catch (e) {
    return null;
  }
}
function ls_set(k, v) {
  try {
    localStorage.setItem(k, JSON.stringify(v));
  } catch (e) {
    showToast("⚠️ Storage full — clear some space!");
  }
}
function ls_rm(k) {
  localStorage.removeItem(k);
}

function showToast(msg, dur = 3200) {
  const t = document.getElementById("toast");
  if (!t) return;
  t.textContent = msg;
  t.classList.remove("hidden");
  clearTimeout(t._tid);
  t._tid = setTimeout(() => t.classList.add("hidden"), dur);
}

function closeM(id) {
  document.getElementById(id)?.classList.add("hidden");
}
function openM(id) {
  document.getElementById(id)?.classList.remove("hidden");
}

// ---- NAVBAR ----
function toggleNav() {
  const nl = document.getElementById("navLinks");
  if (!nl) return;
  nl.classList.toggle("open");
  // close on outside click
  if (nl.classList.contains("open")) {
    setTimeout(() => {
      document.addEventListener("click", closeNavOutside, { once: true });
    }, 10);
  }
}
function closeNavOutside(e) {
  const nl = document.getElementById("navLinks");
  const ham =
    document.getElementById("hamBtn") || document.querySelector(".ham");
  if (nl && !nl.contains(e.target) && e.target !== ham) {
    nl.classList.remove("open");
  }
}

// Close nav on link click
document.addEventListener("DOMContentLoaded", () => {
  document.querySelectorAll(".navlinks .nl").forEach((a) => {
    a.addEventListener("click", () => {
      document.getElementById("navLinks")?.classList.remove("open");
    });
  });
  // init page-specific
  const path = location.pathname;
  if (path.includes("admin")) initAdminPage();
  else if (path.includes("campus")) {
  } // loadCampusPage called inline
  else initIndexPage();
});

