// ---- PHOTO UPLOAD ----
function handlePic(e) {
  const file = e.target.files[0];
  if (!file) return;
  if (file.size > 5 * 1024 * 1024) {
    showToast("❌ Image too large! Max 5MB bestie 😅");
    return;
  }
  const reader = new FileReader();
  reader.onload = (ev) => {
    const prev = document.getElementById("picPreview");
    const ph = document.getElementById("uploadPH");
    if (prev) {
      prev.src = ev.target.result;
      prev.classList.remove("hidden");
    }
    if (ph) ph.classList.add("hidden");
  };
  reader.readAsDataURL(file);
}

// ---- CONTACT SUBMISSION ----
function submitContact() {
  const name = document.getElementById("fName")?.value.trim();
  const phone = document.getElementById("fPhone")?.value.trim();
  const inst = document.getElementById("fInst")?.value;
  const course = document.getElementById("fCourse")?.value.trim();
  const year = document.getElementById("fYear")?.value;
  const bio = document.getElementById("fBio")?.value.trim();
  const photo = document.getElementById("picPreview")?.src;
  const terms = document.getElementById("termsChk")?.checked;

  if (!name) {
    showToast("❌ What's your name fam? 😭");
    return;
  }
  if (!phone || phone.length < 9) {
    showToast("❌ Drop a valid WhatsApp number fr 📱");
    return;
  }
  if (!inst) {
    showToast("❌ Where do you go to school? 🏛️");
    return;
  }
  if (!course) {
    showToast("❌ What's your course bestie? 📚");
    return;
  }
  if (!photo || photo === window.location.href) {
    showToast("❌ Drop your pic first! No photo no save 😤");
    return;
  }
  if (!terms) {
    showToast("❌ Read the terms first bro 📜");
    return;
  }

  const contacts = ls_get(CONTACTS_KEY) || [];
  // Check duplicate number
  const dup = contacts.find((c) => c.phone === phone);
  if (dup) {
    showToast("⚠️ That number is already in the squad! 👀");
    return;
  }

  const contact = {
    id: Date.now().toString(),
    name,
    phone,
    inst,
    course,
    year,
    bio,
    photo: photo && !photo.endsWith(window.location.href) ? photo : null,
    date: new Date().toLocaleDateString("en-KE"),
  };

  contacts.push(contact);
  ls_set(CONTACTS_KEY, contacts);

  showSuccessModal(contact);
  showToast("🎉 You're in the squad now! Welcome fam 🇰🇪");

  // Reset form
  setTimeout(() => {
    ["fName", "fPhone", "fCourse", "fBio"].forEach((id) => {
      const el = document.getElementById(id);
      if (el) el.value = "";
    });
    ["fInst", "fYear"].forEach((id) => {
      const el = document.getElementById(id);
      if (el) el.selectedIndex = 0;
    });
    const prev = document.getElementById("picPreview");
    if (prev) prev.classList.add("hidden");
    const ph = document.getElementById("uploadPH");
    if (ph) ph.classList.remove("hidden");
    const chk = document.getElementById("termsChk");
    if (chk) chk.checked = false;
  }, 1000);
}

function showSuccessModal(contact) {
  const prev = document.getElementById("savedPreview");
  if (prev) {
    prev.innerHTML = `<div style="display:flex;align-items:center;gap:12px;background:var(--bg3);border:1px solid var(--border);border-radius:12px;padding:14px;margin:14px 0;text-align:left;">
      ${contact.photo ? `<img src="${contact.photo}" style="width:48px;height:48px;border-radius:50%;object-fit:cover;border:2px solid var(--accent);" onerror="this.style.display='none'">` : '<div style="width:48px;height:48px;border-radius:50%;background:var(--bg);display:flex;align-items:center;justify-content:center;font-size:1.4rem;">👤</div>'}
      <div><strong style="display:block;">${contact.name}</strong>
      <span style="color:var(--accent);font-size:0.85rem;">+254${contact.phone}</span>
      <span style="display:block;color:var(--muted2);font-size:0.78rem;">${contact.inst}</span></div>
    </div>`;
  }
  openM("successModal");
}

function downloadMyVCF() {
  const contacts = ls_get(CONTACTS_KEY) || [];
  const me = contacts[contacts.length - 1];
  if (!me) {
    showToast("❌ No contact found!");
    return;
  }
  const vcf = buildVCF(me);
  downloadBlob(vcf, "text/vcard", `${me.name.replace(/\s+/g, "_")}.vcf`);
  showToast("📥 VCF downloaded! Import it on your phone 💪");
}

function buildVCF(c) {
  let v = `BEGIN:VCARD\r\nVERSION:3.0\r\nFN:${c.name}\r\nN:${c.name};;;;`;
  v += `\r\nTEL;TYPE=CELL;TYPE=WHATSAPP:+254${c.phone}`;
  if (c.inst) v += `\r\nORG:${c.inst}`;
  if (c.course) v += `\r\nTITLE:${c.course}`;
  if (c.year)
    v += `\r\nNOTE:${c.year}${c.bio ? " | " + c.bio : ""} | Save4Save 🇰🇪`;
  if (c.photo && c.photo.includes("base64,")) {
    const b64 = c.photo.split("base64,")[1];
    v += `\r\nPHOTO;ENCODING=b;TYPE=JPEG:${b64}`;
  }
  v += `\r\nEND:VCARD`;
  return v;
}

function downloadBlob(content, mime, filename) {
  const blob = new Blob([content], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

