// ---- CONTACTS TABLE ----
function loadContactsTable() {
  const contacts = ls_get(CONTACTS_KEY) || [];
  const tbody = document.getElementById("ctbody");
  const empty = document.getElementById("emptyTbl");
  if (!tbody) return;

  if (contacts.length === 0) {
    tbody.innerHTML = "";
    empty?.classList.remove("hidden");
    return;
  }
  empty?.classList.add("hidden");
  renderContactRows(contacts, tbody);
}

function renderContactRows(contacts, tbody) {
  tbody.innerHTML = contacts
    .map(
      (c) => `
    <tr>
      <td>${c.photo ? `<img class="ct-avatar" src="${c.photo}" alt="" onerror="this.parentElement.innerHTML='<div class=ct-av-placeholder>👤</div>'">` : '<div class="ct-av-placeholder">👤</div>'}</td>
      <td><strong>${esc(c.name)}</strong></td>
      <td><a href="https://wa.me/254${c.phone}" target="_blank" style="color:var(--accent);text-decoration:none;">+254${esc(c.phone)}</a></td>
      <td style="font-size:0.82rem;color:var(--muted2);">${esc(c.inst || "—")}</td>
      <td style="font-size:0.82rem;">${esc(c.course || "—")}</td>
      <td style="font-size:0.82rem;color:var(--muted2);">${esc(c.year || "—")}</td>
      <td style="font-size:0.78rem;color:var(--muted);">${esc(c.date || "—")}</td>
      <td>
        <div style="display:flex;gap:6px;flex-wrap:wrap;">
          <button class="btn-sm-green" onclick="dlOneVCF('${c.id}')" style="padding:6px 12px;font-size:0.78rem;"><i class="fas fa-download"></i></button>
          <button class="btn-danger" onclick="confirmDelete('${c.id}')" style="padding:6px 12px;font-size:0.78rem;"><i class="fas fa-trash"></i></button>
        </div>
      </td>
    </tr>`,
    )
    .join("");
}

function filterContacts() {
  const q = document.getElementById("srch")?.value.toLowerCase().trim();
  const contacts = ls_get(CONTACTS_KEY) || [];
  const filtered = q
    ? contacts.filter(
        (c) =>
          (c.name || "").toLowerCase().includes(q) ||
          (c.phone || "").includes(q),
      )
    : contacts;
  const tbody = document.getElementById("ctbody");
  const empty = document.getElementById("emptyTbl");
  if (filtered.length === 0) {
    empty?.classList.remove("hidden");
    if (tbody) tbody.innerHTML = "";
  } else {
    empty?.classList.add("hidden");
    if (tbody) renderContactRows(filtered, tbody);
  }
}

let _delId = null;
function confirmDelete(id) {
  _delId = id;
  const btn = document.getElementById("delConfirmBtn");
  if (btn) btn.onclick = doDelete;
  openM("delModal");
}

function doDelete() {
  let contacts = ls_get(CONTACTS_KEY) || [];
  contacts = contacts.filter((c) => c.id !== _delId);
  ls_set(CONTACTS_KEY, contacts);
  closeM("delModal");
  loadContactsTable();
  updateAdminStats();
  showToast("🗑️ Contact deleted fr fr.");
}

function dlOneVCF(id) {
  const contacts = ls_get(CONTACTS_KEY) || [];
  const c = contacts.find((x) => x.id === id);
  if (!c) {
    showToast("❌ Contact not found!");
    return;
  }
  downloadBlob(buildVCF(c), "text/vcard", `${c.name.replace(/\s+/g, "_")}.vcf`);
  showToast(`📥 Downloaded VCF for ${c.name}`);
}

function dlAllVCF() {
  const contacts = ls_get(CONTACTS_KEY) || [];
  if (!contacts.length) {
    showToast("😅 No contacts yet!");
    return;
  }
  const all = contacts.map(buildVCF).join("\r\n");
  downloadBlob(all, "text/vcard", "Save4Save_AllContacts.vcf");
  showToast(`📥 Downloaded ${contacts.length} contacts as VCF!`);
}

