function addSkill() {
  const n = document.getElementById("newSkillName")?.value.trim();
  const l = parseInt(document.getElementById("newSkillLevel")?.value) || 70;
  if (!n) {
    showToast("❌ Enter a skill name!");
    return;
  }
  const skills = ls_get(SKILLS_KEY) || [];
  skills.push({ name: n, level: Math.min(100, Math.max(1, l)) });
  ls_set(SKILLS_KEY, skills);
  loadSkillsEditor();
  document.getElementById("newSkillName").value = "";
  document.getElementById("newSkillLevel").value = "";
  showToast("💪 Skill added!");
}

function delSkill(i) {
  const skills = ls_get(SKILLS_KEY) || [];
  skills.splice(i, 1);
  ls_set(SKILLS_KEY, skills);
  loadSkillsEditor();
}

