function getDefaultPhotos() {
  return DEFAULT_CAMPUS_PHOTOS;
}

// ============================================================
//  CAMPUS PAGE
// ============================================================
function loadCampusPage() {
  renderCampusGrid("all");
  updateCampusStats();
}

function getAllCampusPhotos() {
  const uploaded = ls_get(PHOTOS_KEY) || [];
  const defaults = getDefaultPhotos();
  // Merge: uploaded first (newest), then defaults, no duplicate ids
  const uploadedIds = new Set(uploaded.map((p) => p.id));
  const merged = [
    ...uploaded,
    ...defaults.filter((p) => !uploadedIds.has(p.id)),
  ];
  return merged;
}

function updateCampusStats() {
  const photos = getAllCampusPhotos();
  const campusPhotos = photos.filter(
    (p) => p.target === "campus" || p.target === "both",
  );
  const totalLikes = campusPhotos.reduce((a, p) => a + (p.likes || 0), 0);
  const totalComments = campusPhotos.reduce(
    (a, p) => a + (p.comments?.length || 0),
    0,
  );
  const el_p = document.getElementById("totalPhotos");
  const el_l = document.getElementById("totalLikes");
  const el_c = document.getElementById("totalComments");
  if (el_p) el_p.textContent = campusPhotos.length;
  if (el_l) el_l.textContent = totalLikes;
  if (el_c) el_c.textContent = totalComments;
}

function filterCampus(cat, btn) {
  document
    .querySelectorAll(".cf-btn")
    .forEach((b) => b.classList.remove("active"));
  btn?.classList.add("active");
  renderCampusGrid(cat);
}

function renderCampusGrid(cat) {
  const photos = getAllCampusPhotos();
  const campusPhotos = photos.filter(
    (p) => p.target === "campus" || p.target === "both",
  );
  const filtered =
    cat === "all" ? campusPhotos : campusPhotos.filter((p) => p.cat === cat);

  const grid = document.getElementById("campusGrid");
  const empty = document.getElementById("campusEmpty");
  if (!grid) return;

  if (!filtered.length) {
    grid.innerHTML = "";
    empty?.classList.remove("hidden");
    return;
  }
  empty?.classList.add("hidden");

  grid.innerHTML = filtered
    .map((p) => {
      const liked = isLiked(p.id);
      return `<div class="cg-card" onclick="openPhotoModal('${p.id}')">
      <div class="cg-img-wrap">
        <img src="${p.src}" alt="${esc(p.inst)}" loading="lazy" onerror="this.style.opacity='0.3';this.style.filter='grayscale(1)'">
      </div>
      <div class="cg-body">
        <div class="cg-inst">${esc(p.inst)}</div>
        <div class="cg-caption">${esc(p.caption || "")}</div>
        <div class="cg-foot">
          <span class="cg-cat">${catLabel(p.cat)}</span>
          <button class="like-btn ${liked ? "liked" : ""}" onclick="event.stopPropagation();toggleLike('${p.id}',this)">
            <i class="fas fa-heart"></i> <span>${p.likes || 0}</span>
          </button>
        </div>
      </div>
    </div>`;
    })
    .join("");
}

function catLabel(cat) {
  const map = {
    university: "🎓 University",
    kmtc: "🏥 KMTC",
    college: "🏫 College",
    moments: "✨ Moments",
  };
  return map[cat] || cat;
}

function isLiked(id) {
  const liked = JSON.parse(sessionStorage.getItem("s4s_likes") || "[]");
  return liked.includes(id);
}

function toggleLike(id, btn) {
  const photos = ls_get(PHOTOS_KEY) || [];
  const idx = photos.findIndex((p) => p.id === id);
  if (idx === -1) return;
  const liked = JSON.parse(sessionStorage.getItem("s4s_likes") || "[]");
  const already = liked.includes(id);
  if (already) {
    photos[idx].likes = Math.max(0, (photos[idx].likes || 1) - 1);
    sessionStorage.setItem(
      "s4s_likes",
      JSON.stringify(liked.filter((x) => x !== id)),
    );
    btn?.classList.remove("liked");
  } else {
    photos[idx].likes = (photos[idx].likes || 0) + 1;
    liked.push(id);
    sessionStorage.setItem("s4s_likes", JSON.stringify(liked));
    btn?.classList.add("liked");
  }
  const countEl = btn?.querySelector("span");
  if (countEl) countEl.textContent = photos[idx].likes;
  ls_set(PHOTOS_KEY, photos);
  updateCampusStats();
}

// PHOTO MODAL
let _currentPhotoId = null;

function openPhotoModal(id) {
  const photos = ls_get(PHOTOS_KEY) || [];
  const p = photos.find((x) => x.id === id);
  if (!p) return;
  _currentPhotoId = id;

  const img = document.getElementById("modalPhoto");
  const inst = document.getElementById("modalInst");
  const caption = document.getElementById("modalCaption");
  const cat = document.getElementById("modalCat");
  const likeBtn = document.getElementById("modalLikeBtn");
  const likeCount = document.getElementById("modalLikeCount");
  const commentsList = document.getElementById("modalCommentsList");

  if (img) {
    img.src = p.src;
    img.onerror = () => (img.style.display = "none");
  }
  if (inst) inst.textContent = p.inst;
  if (caption) caption.textContent = p.caption || "";
  if (cat) cat.textContent = catLabel(p.cat);
  if (likeCount) likeCount.textContent = p.likes || 0;
  if (likeBtn) {
    likeBtn.className = "like-btn-modal" + (isLiked(id) ? " liked" : "");
  }

  renderModalComments(p.comments || []);
  openM("photoModal");
}

function renderModalComments(comments) {
  const list = document.getElementById("modalCommentsList");
  if (!list) return;
  if (!comments.length) {
    list.innerHTML =
      '<div style="color:var(--muted);font-size:0.82rem;text-align:center;padding:10px;">No comments yet — be the first! 🔥</div>';
    return;
  }
  list.innerHTML = comments
    .map(
      (c) =>
        `<div class="comment-item"><strong>${esc(c.name)}</strong>${esc(c.text)}</div>`,
    )
    .join("");
}

function toggleModalLike() {
  if (!_currentPhotoId) return;
  const btn = document.getElementById("modalLikeBtn");
  const photos = ls_get(PHOTOS_KEY) || [];
  const idx = photos.findIndex((p) => p.id === _currentPhotoId);
  if (idx === -1) return;
  const liked = JSON.parse(sessionStorage.getItem("s4s_likes") || "[]");
  const already = liked.includes(_currentPhotoId);
  if (already) {
    photos[idx].likes = Math.max(0, (photos[idx].likes || 1) - 1);
    sessionStorage.setItem(
      "s4s_likes",
      JSON.stringify(liked.filter((x) => x !== _currentPhotoId)),
    );
    btn?.classList.remove("liked");
  } else {
    photos[idx].likes = (photos[idx].likes || 0) + 1;
    liked.push(_currentPhotoId);
    sessionStorage.setItem("s4s_likes", JSON.stringify(liked));
    btn?.classList.add("liked");
  }
  const lc = document.getElementById("modalLikeCount");
  if (lc) lc.textContent = photos[idx].likes;
  ls_set(PHOTOS_KEY, photos);
  updateCampusStats();
}

function submitModalComment() {
  const name = document.getElementById("modalCommentName")?.value.trim();
  const text = document.getElementById("modalCommentText")?.value.trim();
  if (!name || !text) {
    showToast("❌ Drop your name and comment bestie!");
    return;
  }

  const photos = ls_get(PHOTOS_KEY) || [];
  const idx = photos.findIndex((p) => p.id === _currentPhotoId);
  if (idx === -1) return;
  if (!photos[idx].comments) photos[idx].comments = [];
  photos[idx].comments.push({
    name,
    text,
    date: new Date().toLocaleDateString("en-KE"),
  });
  ls_set(PHOTOS_KEY, photos);

  renderModalComments(photos[idx].comments);
  updateCampusStats();

  const nn = document.getElementById("modalCommentName");
  const nt = document.getElementById("modalCommentText");
  if (nn) nn.value = "";
  if (nt) nt.value = "";
  showToast("💬 Comment dropped fr fr!");
}

// ---- HELPERS ----
function esc(s) {
  return String(s || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

