//  ABOUT PAGE
// ============================================================

const DEFAULT_SKILLS = [
  { name: "Web Development", level: 85 },
  { name: "JavaScript", level: 80 },
  { name: "Network Building", level: 90 },
  { name: "Problem Solving", level: 88 },
  { name: "Communication", level: 92 },
  { name: "Python", level: 70 },
];

const DEFAULT_EXPERIENCE = [
  {
    role: "Founder & Network Admin",
    org: "Save4Save — Kenya Student Network",
    dur: "2024 – Present",
  },
  {
    role: "Student",
    org: "Karatina University, Nyeri County",
    dur: "2023 – Present",
  },
  {
    role: "Community Builder",
    org: "Kenyan Student Networks",
    dur: "2023 – Present",
  },
];

function loadAboutPage() {
  // Load profile from localStorage or use defaults
  const p = ls_get(ADMIN_PROF_KEY) || {};
  const photo = ls_get(ADMIN_PHOTO_KEY) || ADMIN_PHOTO_SRC;

  // Hero avatar - show George's photo
  const ava = document.getElementById("profileAvaBig");
  const avaImg = document.getElementById("profileAvaImg");
  const avaEmoji = document.getElementById("profileAvaEmoji");
  const photoSrc = photo || ADMIN_PHOTO_SRC;
  if (avaImg && photoSrc) {
    avaImg.src = photoSrc;
    avaImg.style.display = "block";
    if (avaEmoji) avaEmoji.style.display = "none";
    avaImg.onerror = function () {
      this.style.display = "none";
      if (avaEmoji) avaEmoji.style.display = "";
    };
  }

  // Name & bio
  const heroName = document.getElementById("profileHeroName");
  const heroBio = document.getElementById("profileHeroBio");
  const bioText = document.getElementById("aboutBioText");
  if (heroName) heroName.textContent = p.name || "George M.";
  if (heroBio && p.bio) heroBio.textContent = p.bio;
  if (bioText && p.bio) bioText.textContent = p.bio;

  // Side cards
  const course = document.getElementById("adminCourseDisplay");
  const year = document.getElementById("adminYearDisplay");
  const inst = document.getElementById("adminInstDisplay");
  const netw = document.getElementById("networkSizeDisplay");
  if (course) course.textContent = p.course || "BSc Information Technology";
  if (year) year.textContent = p.year || "Year 3 — We cooking 🔥";
  if (inst) inst.textContent = p.inst || "Karatina University";
  const contacts = ls_get(CONTACTS_KEY) || [];
  if (netw) netw.textContent = contacts.length + " contacts";

  // Experience timeline
  loadAboutExperience();

  // Skills
  loadAboutSkills();

  // Gallery
  loadAboutGallery();
}

function switchAboutTab(tab, btn) {
  document
    .querySelectorAll(".atab-panel")
    .forEach((p) => p.classList.add("hidden"));
  document
    .querySelectorAll(".atab")
    .forEach((b) => b.classList.remove("active"));
  document.getElementById("tab-" + tab)?.classList.remove("hidden");
  btn?.classList.add("active");
}

function loadAboutExperience() {
  const exps = ls_get(EXP_KEY) || DEFAULT_EXPERIENCE;
  const el = document.getElementById("expTimeline");
  if (!el) return;
  if (!exps.length) {
    el.innerHTML =
      '<p style="color:var(--muted2);font-size:0.9rem;">No experience added yet. Admin can add from the panel. 😅</p>';
    return;
  }
  el.innerHTML = exps
    .map(
      (e) => `
    <div class="exp-item">
      <div class="exp-role">${esc(e.role || "Role")}</div>
      <div class="exp-org">${esc(e.org || "Organisation")}</div>
      <div class="exp-dur"><i class="fas fa-calendar-alt" style="color:var(--muted);margin-right:5px;"></i>${esc(e.dur || "")}</div>
    </div>`,
    )
    .join("");
}

function loadAboutSkills() {
  const skills = ls_get(SKILLS_KEY) || DEFAULT_SKILLS;
  const el = document.getElementById("skillsGrid");
  if (!el) return;
  if (!skills.length) {
    el.innerHTML =
      '<p style="color:var(--muted2);font-size:0.9rem;">No skills added yet. Add from admin panel! 💪</p>';
    return;
  }
  el.innerHTML = skills
    .map(
      (s) => `
    <div class="skill-item">
      <div class="skill-name-row">
        <span class="skill-name">${esc(s.name)}</span>
        <span class="skill-pct">${s.level}%</span>
      </div>
      <div class="skill-track">
        <div class="skill-fill" style="width:0%" data-width="${s.level}%"></div>
      </div>
    </div>`,
    )
    .join("");

  // Animate bars after paint
  requestAnimationFrame(() => {
    setTimeout(() => {
      document.querySelectorAll(".skill-fill").forEach((bar) => {
        bar.style.width = bar.dataset.width;
      });
    }, 120);
  });
}

function loadAboutGallery() {
  const photos = ls_get(PHOTOS_KEY) || [];
  const gallery = photos.filter(
    (p) => p.target === "about" || p.target === "both",
  );
  const grid = document.getElementById("aboutGallery");
  const empty = document.getElementById("galleryEmpty");
  if (!grid) return;

  if (!gallery.length) {
    if (empty) empty.style.display = "";
    return;
  }
  if (empty) empty.style.display = "none";

  grid.innerHTML = gallery
    .map(
      (p) => `
    <div class="gallery-item" onclick="openPhotoModal('${p.id}')">
      <div class="gallery-img">
        <img src="${p.src}" alt="${esc(p.caption || p.inst)}" loading="lazy" onerror="this.style.opacity='0.2'">
      </div>
      <div class="gallery-caption">${esc(p.caption || p.inst || "")}</div>
    </div>`,
    )
    .join("");
}
